// RegisterTools registers all API operations as MCP tools.
func RegisterTools(s *server.MCPServer) {
	s.AddTool(
		mcplib.NewTool("registrar_domain-check",
			mcplib.WithDescription("Real-time domain availability and pricing check. Must be run immediately before registration. Required: account_id, domain_name. Sends Cloudflare body {domains:[domain_name]}. Returns the DomainCheckResponse."),
			mcplib.WithString("account_id", mcplib.Required(), mcplib.Description("Account id")),
			mcplib.WithString("domain_name", mcplib.Required(), mcplib.Description("Fully qualified domain name to check, e.g. example.dev.")),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		handleRegistrarDomainCheck,
	)
	s.AddTool(
		mcplib.NewTool("registrar_domain-register",
			mcplib.WithDescription("Register a domain through Cloudflare Registrar using account default registrant/payment settings. Dangerous: caller must run domain-check first and pass confirm_domain exactly equal to domain_name after reviewing price. Required: account_id, domain_name, confirm_domain. Returns the RegistrationResponse."),
			mcplib.WithString("account_id", mcplib.Required(), mcplib.Description("Account id")),
			mcplib.WithString("domain_name", mcplib.Required(), mcplib.Description("Fully qualified domain name to register.")),
			mcplib.WithString("confirm_domain", mcplib.Required(), mcplib.Description("Repeat exact domain_name after a fresh domain-check price review.")),
			mcplib.WithDestructiveHintAnnotation(true),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		handleRegistrarDomainRegister,
	)
	s.AddTool(
		mcplib.NewTool("registrar_domain-search",
			mcplib.WithDescription("Search Cloudflare Registrar for domain suggestions and availability hints. Use domain-check for live final pricing before registering. Required: account_id, query. Optional: limit (default: 20). Returns the DomainSearchResponse."),
			mcplib.WithString("account_id", mcplib.Required(), mcplib.Description("Account id")),
			mcplib.WithString("query", mcplib.Required(), mcplib.Description("Search query or base name.")),
			mcplib.WithString("limit", mcplib.Description("Limit")),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("GET", "/accounts/{account_id}/registrar/domain-search", []mcpParamBinding{{PublicName: "account_id", WireName: "account_id", Location: "path"}, {PublicName: "query", WireName: "q", Location: "query"}, {PublicName: "limit", WireName: "limit", Location: "query"}}, []string{"account_id"}),
	)
	// SQL tool — ad-hoc analysis on synced data without API calls
	s.AddTool(
		mcplib.NewTool("sql",
			mcplib.WithDescription("Run read-only SQL against local database. Use for ad-hoc analysis, aggregations, and joins across synced resources. Requires sync first."),
			mcplib.WithString("query", mcplib.Required(), mcplib.Description("SQL query (SELECT or WITH...SELECT). Tables match resource names.")),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
		),
		handleSQL,
	)

	// Context tool — front-loaded domain knowledge for agents.
	// Call this first to understand the API taxonomy, query patterns, and capabilities.
	s.AddTool(
		mcplib.NewTool("context",
			mcplib.WithDescription("Get API domain context: resource taxonomy, auth requirements, query tips, and unique capabilities. Call this first."),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
		),
		handleContext,
	)

	// Runtime Cobra-tree mirror — exposes every user-facing command that is
	// not already covered by a typed endpoint or framework MCP tool.
	cobratree.RegisterAll(s, cli.RootCmd(), cobratree.SiblingCLIPath)
}

